import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import response from './response.json';

interface Build {
  buildId: string;
  status: string;
  duration: string;
}

interface CICDPipelineData {
  recentBuilds: Build[];
  successRate: number;
  averageDeployTime: string;
}

export default function Widget() {
  const cicdData = response.data as CICDPipelineData;
  const { recentBuilds, successRate, averageDeployTime } = cicdData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#1E1E1E', color: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ mb: 1 }}>
              Build Monitor
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Success Rate: {successRate}%
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Avg Deploy Time: {averageDeployTime}
            </Typography>
          </Box>

          <Stack spacing={1}>
            {recentBuilds.map((build) => (
              <Stack key={build.buildId} direction="row" justifyContent="space-between" alignItems="center">
                <Chip 
                  label={build.buildId} 
                  sx={{ fontSize: '11px', color: '#FFFFFF', bgcolor: build.status === 'success' ? '#10B981' : '#EF4444' }}
                />
                <Typography variant="body2" sx={{ color: '#D1D5DB' }}>
                  {build.duration}
                </Typography>
              </Stack>
            ))}
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
